import { Component, h, Prop, Element } from '@stencil/core';

@Component({
  tag: 'wdpr-linear-loader',
  shadow: true,
})
export class WdprLinearLoader {
  /**
   * Reference to host element
   * @type {HTMLWdprLinearLoaderElement}
   */
  @Element() el: HTMLWdprLinearLoaderElement;

  /**
   * Progress of the bar
   */
  @Prop({ reflect: true }) progress: number = 0;

  /**
   * Maximum progress of the bar
   * @type {HTMLWdprLinearLoaderElement}
   */
  @Prop({ reflect: true }) max: number = 100;

  private get percentage() {
    if (this.progress >= this.max) return 100;
    if (this.progress <= 0) return 0;

    return (this.progress / this.max) * 100;
  }

  render() {
    return (
      <div
        class="flex flex-col gap-050 w-full"
        role="progressbar"
        aria-valuenow={this.progress}
        aria-valuemin={0}
        aria-valuemax={this.max}
        aria-label={`Loading progress: ${this.progress} out of ${this.max}`}
      >
        <div class="w-full bg-black rounded-pill h-100 overflow-hidden">
          <div
            class="bg-white h-full transition-all duration-500 ease-in-out"
            style={{ width: `${this.percentage}%` }}
          ></div>
        </div>
      </div>
    );
  }
}
